def _persist_stub(name, file_path="runner/auto_ops.py"):
    # persiste un stub dans un fichier de stubs
    from pathlib import Path
    path = Path(file_path)
    path.parent.mkdir(parents=True, exist_ok=True)
    line = f"\n\ndef {name}(args):\n    return {{\"ok\": True, \"op\": \"{name}\", \"note\": \"auto stub\"}}\n"
    if path.exists():
        txt = path.read_text(encoding="utf-8")
        if f"def {name}(" in txt:
            return
        path.write_text(txt + line, encoding="utf-8")
    else:
        header = "# auto ops stubs\n"
        path.write_text(header + line, encoding="utf-8")

