def _ops_from_spec(spec):
    req = []
    for st in spec.get("steps", []):
        op = st.get("op")
        if op and op not in req:
            req.append(op)
    return req

def ensure_ops_for_spec(spec, persist=True):
    created = []
    for op in _ops_from_spec(spec):
        if op in OPS:
            continue
        fn = _op_stub_factory(op)
        _op_register(op, fn)
        if persist:
            _op_persist_stub(op)
        created.append(op)
    return {"created": created, "count": len(created)}

# hooks
def _run_phase_hooks(phase, op_name, ctx):
    # ctx attend agent function_id inputs outputs
    for hook in HOOKS.get(phase, {}).get(op_name, []):
        try:
            hook({**ctx, "phase": phase, "op": op_name})
        except Exception as e:
            rec = {
                "level": "alert",
                "phase": phase,
                "op": op_name,
                "hook": getattr(hook, "__name__", "unknown"),
                "error": str(e),
                "ts": _now_ts(),
            }
            _append_jsonl("09_logs/pipeline.jsonl", rec)

