# hook auto ops after pour function.create et method.create
def _hook_auto_ops_after_create(ctx):
    import re
    outs = ctx.get("outputs") or []
    targets = []
    for p in outs:
        sp = str(p)
        if re.search(r"\.(function|method)\.json$", sp):
            targets.append(sp)
    results = []
    for t in targets:
        spec = _json_read(t, {})
        res = ensure_ops_for_spec(spec, persist=True)
        results.append({"file": t, **res})
    rec = {
        "level": "info",
        "phase": "after",
        "hook": "auto_ops_after_create",
        "files": targets,
        "results": results,
        "ts": _now_ts(),
    }
    _append_jsonl("09_logs/audit.jsonl", rec)
    return {"ok": True, "handled": len(targets)}

# carte des hooks
HOOKS = {
    "before": {
        # rien par defaut
    },
    "after": {
        "execute_GEVR_steps": [audit_execute_GEVR],
        "function.create": [_hook_auto_ops_after_create],
        "method.create":   [_hook_auto_ops_after_create],
    },
    "on_failure": {
        # rien par defaut
    },
}

# wrapper avec hooks
def run_op_with_hooks(op, args, ctx):
    start = time.time()
    try:
        # no log before dans pipeline
        res = OPS[op](args)
        dur = int((time.time() - start) * 1000)
        ctx["status"] = "success"
        ctx["started_at"] = ctx.get("started_at") or datetime.fromtimestamp(start, tz=timezone.utc).isoformat().replace("+00:00","Z")
        ctx["finished_at"] = datetime.now(timezone.utc).isoformat().replace("+00:00","Z")
        ctx["duration_ms"] = dur
        _run_phase_hooks("after", op, ctx)
        return res
    except Exception as e:
        rec = {
            "level": "alert",
            "phase": "on_failure",
            "op": op,
            "error": str(e),
            "agent": ctx.get("agent"),
            "function_id": ctx.get("function_id"),
            "inputs": ctx.get("inputs"),
            "outputs": ctx.get("outputs"),
            "ts": _now_ts(),
        }
        _append_jsonl("09_logs/pipeline.jsonl", rec)
        _run_phase_hooks("on_failure", op, {**ctx, "error": str(e)})
        raise

