    tasks_obj = _json_read(tasks_path, {"tasks": []})
    tasks = tasks_obj.get("tasks", [])
    present = set()
    labeled = []
    for t in tasks:
        name = t.get("id") or t.get("name") or "T"
        cls = t.get("class")
        if cls not in {"G","E","V","R"}:
            # naive attribution
            if name.lower().endswith("01") or name.lower().endswith("_g"):
                cls = "G"
            elif name.lower().endswith("02") or name.lower().endswith("_e"):
                cls = "E"
            elif name.lower().endswith("03") or name.lower().endswith("_v"):
                cls = "V"
            elif name.lower().endswith("04") or name.lower().endswith("_r"):
                cls = "R"
            else:
                cls = "G"
        present.add(cls)
        labeled.append({**t, "class": cls})
    _json_write(labeled_path, {"tasks": labeled})
    expected = ["E","G","V","R"]
    missing = [c for c in expected if c not in present]
    checks = _json_read(checks_path, {})
    checks["gever_expected"] = expected
    checks["gever_present"] = sorted(list(present))
    checks["gever_missing"] = missing
    _json_write(checks_path, checks)
    return {"ok": True, "present": sorted(list(present)), "missing": missing}

