from pathlib import Path, json

def load_forbid():
    forbid=set()
    for c in ["01_params/Params.json","Params.json"]:
        p=Path(c)
        if p.exists():
            try:
                data=json.loads(p.read_text(encoding="utf-8"))
            except Exception:
                data={}
            gever=(data or {}).get("GEVER") or {}
            for k in (data.get("forbid_ghost"), gever.get("forbid_ghost")):
                if isinstance(k, list):
                    forbid.update(str(x) for x in k)
    return forbid

def banned(step, forbid):
    if not isinstance(step, dict):
        return False
    sid=str(step.get("id") or step.get("step_id") or "")
    cls=str(step.get("class") or "")
    return bool(sid) and bool(cls) and sid.endswith(f"Ghost_{cls}") and cls in forbid

idx=Path("08_objects/steps/index.json")
if idx.exists():
    try:
        data=json.loads(idx.read_text(encoding="utf-8") or "{}")
    except Exception:
        data={}
    if isinstance(data, list):
        steps=data
        fg=load_forbid()
        kept=[s for s in steps if not banned(s, fg)]
        if len(kept)!=len(steps):
            idx.write_text(json.dumps(kept, ensure_ascii=False, indent=2), encoding="utf-8")
            print("sanitize_ok")
        else:
            print("sanitize_clean")
    else:
        steps=data.get("steps") or data.get("Steps") or data.get("items") or []
        if isinstance(steps, list):
            fg=load_forbid()
            kept=[s for s in steps if not banned(s, fg)]
            if len(kept)!=len(steps):
                if "steps" in data: data["steps"]=kept
                elif "Steps" in data: data["Steps"]=kept
                elif "items" in data: data["items"]=kept
                idx.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
                print("sanitize_ok")
            else:
                print("sanitize_clean")
        else:
            print("sanitize_nolist")
else:
    print("sanitize_missing")
