from pathlib import Path
import re, json, glob

candidates = []
candidates += sorted(glob.glob("09_logs/executions*.jsonl"))
if Path("09_logs/executions.jsonl").exists(): candidates.append("09_logs/executions.jsonl")
if Path("07_report/executions.md").exists():   candidates.append("07_report/executions.md")
if Path("09_logs/audit.jsonl").exists():       candidates.append("09_logs/audit.jsonl")
if Path("06_tasks/board.json").exists():       candidates.append("06_tasks/board.json")

steps = {}
def add(sid, cls=""):
    if not sid or "Ghost_E" in sid: return
    steps[sid] = cls or steps.get(sid,"")

for f in candidates:
    p = Path(f)
    if not p.exists(): continue
    txt = p.read_text(encoding="utf-8", errors="ignore")
    for line in txt.splitlines():
        # JSON lines with {"step_id": "...", "class": "..."}
        try:
            o = json.loads(line)
            sid = o.get("step_id") or ""
            cls = o.get("class") or ""
            if sid: add(sid, cls)
            continue
        except Exception:
            pass
        # JSON file (board.json)
        if f.endswith("board.json"):
            try:
                o = json.loads(txt)
                # try common shapes
                for k in ("steps","items","tasks"):
                    if isinstance(o.get(k), list):
                        for it in o[k]:
                            sid = it.get("id") or it.get("step_id") or ""
                            cls = it.get("class") or ""
                            if sid: add(sid, cls)
                continue
            except Exception:
                pass
        # Plain text/markdown patterns
        m = re.search(r'"step_id"\s*:\s*"([^"]+)"', line)
        sid = m.group(1) if m else ""
        if sid:
            m2 = re.search(r'"class"\s*:\s*"([^"]*)"', line)
            cls = m2.group(1) if m2 else ""
            add(sid, cls)

out = {"version":"1","steps":[{"id":k,"class":steps[k]} for k in sorted(steps)]}
Path("08_objects/steps").mkdir(parents=True, exist_ok=True)
Path("08_objects/steps/index.json").write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
print(len(out["steps"]))
PY

